def gen(rng, size):
    n = max(2, min(size, 60))
    vals = rng.sample(range(-10000, 10001), n)
    nodes = [[vals[0], None, None]]
    for v in vals[1:]:
        cur = nodes[0]
        while True:
            if v < cur[0]:
                if cur[1] is None:
                    cur[1] = [v, None, None]
                    break
                cur = cur[1]
            else:
                if cur[2] is None:
                    cur[2] = [v, None, None]
                    break
                cur = cur[2]
    out = []
    queue = [nodes[0]]
    while queue:
        cur = queue.pop(0)
        if cur is None:
            out.append(None)
            continue
        out.append(cur[0])
        queue.append(cur[1])
        queue.append(cur[2])
    while out and out[-1] is None:
        out.pop()
    p, q = rng.sample(vals, 2)
    return [out, p, q]

