class Solution:
    def lowestCommonAncestor(self, root, p, q):
        def path(target):
            out = []
            cur = root
            while cur is not None:
                out.append(cur)
                if target.val == cur.val:
                    return out
                cur = cur.left if target.val < cur.val else cur.right
            return out
        pa, pb = path(p), path(q)
        ans = None
        for a, b in zip(pa, pb):
            if a is b:
                ans = a
        return ans

